INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (105790401, "【物理】特異な力で変質したクリーパー。\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・ニードルクリーパーから受けるすべてのダメー\n　ジで発生する、パーティキャラのＴＰ回復量を\n　中ダウンさせる。\n・ユニオンバーストは、最も近い敵２キャラに物\n　理大ダメージを与え、拘束状態を付与し、ＴＰ\n　を大ダウンさせる。このスキルの状態異常はダ\n　メージを無効化しても付与される。\n・最も近い敵３キャラの物理防御力を大ダウンさ\n　せ、毒状態を付与する。このスキルにより付与\n　された毒のダメージでは、ＴＰが回復しない。");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (105790601, "【物理】大きな皮翼を使い、空を駆ける翼竜。\n巨大な火球を吐き、侵入者の行く手を阻む。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・ワイバーンから受けるすべてのダメージで発生\n　する、パーティキャラのＴＰ回復量を中ダウン\n　させる。\n・ユニオンバーストは、最も近い敵を中心にした\n　広範囲の最大３キャラに物理大ダメージを与え、\n　物理防御力を中ダウンさせる。さらに自身の物\n　理防御力をバトル終了まで小アップさせる。こ\n　のスキルの状態異常はダメージを無効化しても\n　付与される。\n・最も近い敵３キャラをノックバックさせ、行動\n　速度を中ダウンさせる。");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (105800101, "【物理】強力な氷のブレスで前衛を一瞬で\n氷漬けにし、咬みついて身体を砕く獰猛な深海竜。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・シードレイクから受けるすべてのダメージで発\n　生する、パーティキャラのＴＰ回復量を中ダウ\n　ンさせる。\n・ユニオンバーストは、召喚体、分身を除いた最\n　も近い敵３キャラに物理特大ダメージを与え、\n　さらに物理防御力と魔法防御力を特大ダウンさ\n　せる。このスキルの状態異常はダメージを無効\n　化しても付与される。\n・召喚体、分身を除いた最も近い敵２キャラに魔\n　法大ダメージを与え、短時間凍結状態を付与す\n　る。敵キャラのＨＰが70％未満の場合、長時\n　間凍結状態を付与する。このスキルの状態異常\n　はダメージを無効化しても付与される。");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010101, "【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\n幼き戦士を脇に抱え、魂の技を見せ付ける。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に物理ダメージ\n・自身に物理攻撃力アップ\n・自身に物理防御力アップ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010201, "【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\n油断すると、加減知らずの雷撃を見舞われる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ（飛行効果無視）\n【スキル１】\n・後ろから敵３体に魔法ダメージ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010301, "【物理】無数の残骸で再構築された巨大ゴーレム。\n巨岩の腕を振り下ろし、地盤ごと敵を粉砕する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・自身がバリア状態：ダメージアップ\n【スキル１】\n・自身に物理無効バリア\n・自身に魔法無効バリア\n【通常攻撃】\n・前から敵２体に物理ダメージ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010401, "【魔法】魔力の雨が集まり形を成した冷酷な水霊。\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体にスタン（必中）\n・前方範囲ＨＰ70％未満：ノックバック（必中）\n・後方範囲ＨＰ70％未満：引き寄せ（必中）\n【スキル１】\n・後ろから敵１体に魔法ダメージ（挑発無視）\n・後ろから敵１体を引き寄せる（挑発無視・必中）\n・後ろから敵１体に行動速度ダウン（挑発無視・\n　必中）\n【通常攻撃】\n・前から１番目の敵と周囲に魔法ダメージ\n・前から１番目の敵と周囲に物理／魔法攻撃力ダ\n　ウン（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010501, "【魔法】魔力を蓄え雷撃として放電する怪鳥。\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・自身に魔法攻撃力アップ\n・自身に魔法防御力アップ\n【スキル１】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・前から敵１体にＨＰ回復量ダウン（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010601, "【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・敵全体に物理／魔法クリダメダウン（必中）\n【スキル１】\n・自身に物理／魔法防御力アップ\n・敵全体に物理固定ダメージ（飛行効果無視）\n・自身の物理攻撃力が高いほど：ダメージアップ\n【全ターゲットブレイク時発動】\n・自身にクリティカル被ダメージアップ\n・自身にブレイク無効化");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010701, "【物理】特異な力で変質したサベージベア。\n怒りを込めた剛腕は、敵ごと地面を引き裂く。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から１番目の敵と周囲に物理ダメージ\n・前から１番目の敵と周囲にスタン（必中）\n【スキル１】\n・前から１番目の敵と周囲に物理ダメージ\n・前から１番目の敵と周囲に物理防御力ダウン\n　（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010801, "【物理】夢幻より生まれ、闇を彷徨う魔獣。\n悪夢の牢に獲物を縛り、旨そうに生気を喰う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・物理か魔法攻撃力が最も高い敵１体にステータ\n　スアップ解除、魔法ダメージ\n・物理か魔法攻撃力が最も高い敵１体にＴＰダウ\n　ン、呪詛（必中）\n・呪詛状態の敵全体にステータスアップ解除、魔\n　法ダメージ（飛行効果無視）\n【スキル１】\n・挑発無視\n・後ろから１番目の敵と周囲に魔法ダメージ\n・後ろから１番目の敵と周囲に魔法防御力ダウン、\n　ＴＰダウン、呪い（必中）\n【通常攻撃】\n・物理か魔法攻撃力が最も高い敵１体に物理ダ\n　メージ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410010901, "【魔法】海神の使者で、不思議な軟体の魔物。\n身体のほとんどは魔力を帯びた海水だとか。\n\n【特殊効果】\n・挑発無視\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n【スキル１】\n・後ろから２番目の敵を中心に魔法ダメージ\n　フィールド\n【通常攻撃】\n・後ろから２番目の敵に魔法ダメージ\n・後ろから２番目の敵と周囲に行動速度ダウン\n　（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410011001, "【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\n激流は全てを飲込み蒼海の支配者として君臨する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体をノックバック（必中）\n・敵全体にスタン（必中）\n・自身の魔攻が高いほど：スタン時間アップ\n【スキル１】\n・自身に物理／魔法防御力アップ\n・自身にＴＰ継続回復\n・敵全体に物理／魔法防御力ダウン\n【スキル２】\n・前から敵３体に物理ダメージ\n【バトルフィールド効果】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法防御力アップ解除\n・味方全体に物理／魔法防御力ダウン解除");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020101, "【物理】大きな皮翼を使い、空を駆ける翼竜。\n巨大な火球を吐き、侵入者の行く手を阻む。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から１番目の敵と周囲の敵合計４体までに物\n　理ダメージ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020201, "【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\n眠りを妨げると怒り狂い、超能力で暴れまわる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020301, "【物理】魔力を用いてウキキーを統べる仙猿。\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ\n・対象が火傷状態：ダメージアップ\n・敵全体にスタン（必中）\n【スキル１】\n・前から敵３体に物理ダメージ\n【スキル２】\n・前から敵３体に魔法ダメージ\n・前から敵３体に火傷");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020401, "【魔法】不安定な世界の歪みから誕生した特異個\n体の精霊。数奇な擦れ違いを端に暴走し、他の精\n霊たちを巻き込んで里に壊滅の音色を響かせる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ\n・５秒後に対象のＨＰ80％未満：沈黙（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・敵全体にＨＰ吸収ダウン（必中）\n・対象のＨＰ60％未満：束縛（必中）\n【残り時間30秒で発動】\n・自身に魔法攻撃力アップ\n・自身に行動速度アップ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020501, "【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\nその色香に囚われれば、味方を襲う下僕となる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ（ＴＰ回復不可）\n・対象がバリア状態でない：誘惑\n・敵全体に物理／魔法攻撃力アップ（必中）\n【スキル１】\n・前方範囲に魔法ダメージ\n・前方範囲に誘惑（必中）\n・前方範囲に物理／魔法与ダメージダウン（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020601, "【物理】化け茸を統べる気高きキノコの貴族。\n幻覚性の胞子をまき散らし、敵の精神を侵食する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・飛行効果無視\n・敵全体に物理ダメージ\n・対象のＨＰ70％未満：混乱（必中）\n【スキル１】\n・前から敵３体に物理ダメージ（召喚体無視）\n・味方全体に物理攻撃力アップ\n・味方全体に行動速度アップ\n【スキル２】\n・子分４体召喚\n・敵全体をノックバック\n・自身を中心に物理攻撃力アップフィールド、\n　物理／魔法防御力アップフィールド\n【召喚体スキル１】\n・前から敵１体に物理ダメージ\n・対象のＨＰ50％未満：ノックバック（必中）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020701, "【物理】特異な力で変質したエルダーホーン。\n角に魔力を込め、打撃より強力な一撃を放つ。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・物理か魔法攻撃力が最も高い敵１体に魔法ダ\n　メージ（挑発無視）\n・このスキルの対象に物理／魔法攻撃力ダウン、\n　麻痺、継続ＴＰダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・自身にＴＰ回復");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020801, "【物理】特異な力で変質したクリーパー。\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵２体に物理ダメージ（召喚体無視）\n・前から敵２体に束縛（召喚体無視・必中）\n・前から敵２体にＴＰダウン（召喚体無視・必\n　中）\n・前から敵２体に最大ＨＰダウン（召喚体無視・\n　必中）\n【スキル１】\n・前から敵３体に物理防御力ダウン（召喚体無\n　視）\n・前から敵３体に毒（召喚体無視）\n・前から敵３体に物理／魔法クリダメダウン（召\n　喚体無視）");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410020901, "【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・ランダムな敵１体に物理固定ダメージ\n・対象が毒状態：物理固定追加ダメージ\n・対象が猛毒状態：物理固定追加ダメージ\n・上記対象に物理／魔法攻撃力ダウン\n・敵全体にＨＰ吸収ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・対象が毒状態でない：対象に毒\n・対象が毒状態：対象に猛毒\n【通常攻撃】\n・前から敵１体に物理ダメージ\n・前から敵１体に毒");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (410021001, "【物理】大海を背負って立つ、爆走魚座の魔星獣。\n舎弟に魅せるその背中。共に往くのは覇道の極み。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に物理ダメージ\n・自身に行動速度アップ\n・自身に物理攻撃力アップ\n【スキル１】\n・敵全体に物理固定ダメージ\n・旗持ち子分の数が多いほど：物理固定追加ダ\n　メージ\n【スキル２】\n・前から敵２体に物理ダメージ\n・前から敵２体に物理防御力ダウン（必中）\n【スキル３】\n・旗持ち子分を３体召喚\n・自身に物理／魔法防御力ダウン解除\n【召喚体死亡時】\n・敵全体に物理／魔法攻撃力アップ\n・トルペドンに物理／魔法防御力ダウン\n【召喚体スキル１】\n・トルペドンにＴＰ回復");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (502016103, "【物理】ルナの魔力で目覚めた、巨腕の改造人間。\n小型リアクターの最大出力は自身が感電するほど。\n\n【ユニオンバースト】\n・前から敵３体に物理ダメージ\n・前から敵２体に麻痺（必中）\n・自身にステータスアップ解除\n・自身に物理／魔法防御力ダウン\n【スキル１】\n・敵全体に魔法ダメージ\n・自身に物理攻撃力アップ\n【スキル２】\n・味方全体に行動速度アップ\n【スキル３】\n・前から敵２体に物理ダメージ\n【ＨＰ40％未満時発動】\n・自身に行動速度アップ\n・自身に物理攻撃力アップ");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (502016108, "【物理】ルナの塔の魔力で暴走する、古代兵器。\n古き守護の力は、呪いを振りまく大禍と化した。\n\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・自身に物理／魔法防御力ダウン\n【スキル１】\n・前から敵１体と周囲に物理ダメージ\n・前から敵１体と周囲に物理防御力ダウン\n・前から敵１体と周囲にスタン\n【スキル２】\n・敵全体に物理ダメージ\n・敵全体に呪い\n・対象のＨＰが40％未満：呪いのダメージ上昇\n【ＨＰ60％未満時発動】\n・自身に行動速度アップ\n・自身に物理攻撃力アップ\n・行動パターン変化");
INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES (502016111, "【物理】無数の残骸で再構築された巨大ゴーレム。\n巨岩の腕を振り下ろし、地盤ごと敵を粉砕する。\n\n【特殊効果】\n・自身にダメージ減衰\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウン無効\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・自身がバリア状態：ダメージアップ\n【スキル１】\n・自身に物理無効バリア\n・自身に魔法無効バリア\n【通常攻撃】\n・前から敵２体に物理ダメージ");
